+//!
+//! The pipeline enforces variance/confidence guardrails for benchmark evidence so
+//! promotion decisions fail closed when data is noisy or statistically weak.
+
+use std::cmp::Ordering;
+use std::collections::BTreeSet;
+use std::fmt;
+use std::fs;
+use std::path::Path;
