+use thiserror::Error;
+
+pub const PERFORMANCE_STATISTICAL_VALIDATION_COMPONENT: &str = "performance_statistical_validation";
+
+const MILLION: u32 = 1_000_000;
+const SQRT_2: f64 = std::f64::consts::SQRT_2;
